VALUES
  ('real-estate-moex-01332', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '關於經紀人員違反不動產經紀業管理條例之情形中，下列何者並非予以申誡處分？', '["委由經紀業仲介不動產買賣時，經紀業未指派經紀人於法定文件上簽章者", "經紀人員對於因業務知悉或持有之他人秘密，無故洩漏者", "經紀人員收取差價或其他報酬", "經紀人員在執行業務過程中，未以不動產說明書向與委託人交易之相對人解說"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01333', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依不動產經紀業管理條例第19條規定，經紀業或經紀人員不得收取差價或其他報酬，違反規定者之處理， 下列敘述何者正確？', '["其已收取之差價或其他報酬，應返還支付人", "其已收取之差價或其他報酬，應加倍返還支付人", "其已收取之差價或其他報酬，應於加計利息後返還支付人", "其已收取之差價或其他報酬，應於加計利息後加倍返還支付人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01334', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '經紀業應負賠償責任時，受害人於取得對經紀業之執行名義、經仲裁成立或營業保證基金管理委員會之 決議支付後，得於該經紀業繳存營業保證金及提供擔保總額內，向中華民國不動產仲介經紀業或代銷經 紀業同業公會全國聯合會為如何之請求？', '["預為賠償", "代為賠償", "連帶賠償", "不真正連帶賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01335', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '根據不動產說明書應記載及不得記載事項，關於預售屋的其他重要事項，應敘明最近多少時間內基地周 邊半徑多少公尺範圍內有無申請水災淹水救助紀錄？', '["最近3年內基地周邊半徑3百公尺範圍內", "最近3年內基地周邊半徑5百公尺範圍內", "最近5年內基地周邊半徑3百公尺範圍內", "最近5年內基地周邊半徑5百公尺範圍內"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01336', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '不動產經紀人資格的敘述，下列何者正確？', '["經不動產經紀人考試及格者，應具備1年以上經紀營業員經驗，始得向直轄市或縣（市）政府請領經 紀人證書", "經紀人證書有效期限為3年，期滿時，經紀人應檢附其於3年內在中央主管機關認可之機構、團體完 成專業訓練30個小時以上之證明文件，向直轄市或縣（市）政府辦理換證", "經紀人辦理換發證書時，應於證書有效期限屆滿前3個月內，檢附相關文件，向原核發機關申請之", "經紀業不得僱用未具備經紀人員資格者從事仲介或代銷業務，違反者，處新臺幣3萬元以上15萬元 以下罰鍰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01337', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '關於不動產經紀業及經紀人員的敘述，下列何者正確？', '["經營國外不動產仲介業務者，以依法辦理登記之公司或商號為限", "外國人依中華民國法律不得參加不動產經紀人考試或參加營業員訓練", "經紀業取得主管機關許可，依法辦理公司或商業登記，即可開始營業", "經紀業應於經紀人到職之日起15日內，造具名冊報請所在地主管機關層報中央主管機關備查，異動時，亦同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01338', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '不動產經紀業者進行房屋聯賣時，如業者間共同約束實施聯賣之不動產物件開發方擁有一定的專賣期 間，致使已尋得交易相對人之其他不動產經紀業者受限於專賣權之規定而無法成交，對此共同約束行為 之監督管理機關為：', '["內政部營建署", "法務部檢察司", "經濟部商業司", "公平交易委員會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01339', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '某不動產仲介業者甲，為同業競爭之目的，於某社區布告欄張貼散布乙業者有吞沒客戶斡旋金糾紛、浮 報買賣物件開價之不實陳述，致乙業者業績慘跌，營業信譽受損，試問乙得向法院請求之權利，不包含 下列何者？', '["請求除去不法侵害行為", "請求損害賠償", "有侵害之虞時，得請求防止之", "請求精神慰撫金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01340', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '事業違反公平交易法之規定致侵害他人權益者，被害人損害賠償請求權消滅時效的敘述，下列何者正確？', '["自請求權人知有行為及賠償義務人時起，1年間不行使而消滅；自為行為時起，逾5年者亦同", "自請求權人知有行為及賠償義務人時起，1年間不行使而消滅；自為行為時起，逾10年者亦同", "自請求權人知有行為及賠償義務人時起，2年間不行使而消滅；自為行為時起，逾5年者亦同", "自請求權人知有行為及賠償義務人時起，2年間不行使而消滅；自為行為時起，逾10年者亦同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01341', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依公平交易法規定，主管機關為強化聯合行為查處，促進市場競爭秩序之健全發展，得設立何種基金？', '["反托拉斯基金", "管理維護基金", "市場安定基金", "市場重建基金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
